LAYER
	NAME "lagunas"
	GROUP "PY148"
	MAXSCALE -1.0
	MINSCALE -1.0
	TYPE polygon
	PROCESSING "LABEL_NO_CLIP=1"
	PROCESSING "CLOSE_CONNECTION=DEFER"
	DUMP true
	HEADER "plantillas/inicio.html"
	#TEMPLATE "plantillas/uac/py148/lagunas.html"
